#!/usr/bin/env python3
# -*- coding: utf-8 -*-

"""
module_b_phylo_addon.py

模块 B：unresolved 系统发育定位注释增强层
研究口径：公开中药/草本样品数据的二次分析
注意：本模块只做 addon，不改写 sample_type_call.tsv / final_interpretation_notes.tsv 原表

已实现：
1. unresolved 主/备路径
2. kingdom/domain prescreen
3. 仅 fungal_supported 进入 placement
4. threshold_used + 97/98.5/99 敏感性分析
5. sample_type_call_phylo_addon.tsv / final_interpretation_notes_phylo_addon.tsv
6. placement 失败时 -> Level_C observation
7. Level_A/B/C 的“保守项目版”默认规则（证据等级，不等于新分类单元）

未伪造的部分：
- 真正的 EPA-ng / pplacer placement 依赖你本地已准备好的 reference tree / alignment / model
- 如果这些资源不存在，脚本自动降级为 observation 路径，不会假装已有 placement 结果
"""

from __future__ import annotations

import argparse
import csv
import json
import math
import shutil
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, Iterable, List, Optional, Tuple

import pandas as pd

# =========================
# 常量与错误码
# =========================

STEP6B_E010_INPUT_ALIAS_NOT_FOUND = "STEP6B_E010_INPUT_ALIAS_NOT_FOUND"
STEP6B_E011_NOTE_NOT_SAMPLE_LEVEL = "STEP6B_E011_NOTE_NOT_SAMPLE_LEVEL"
STEP6B_E012_THRESHOLD_NOT_RECORDED = "STEP6B_E012_THRESHOLD_NOT_RECORDED"

SENSITIVITY_THRESHOLDS = [97.0, 98.5, 99.0]

REQUIRED_LOGICAL_INPUTS = [
    "annotation_confidence.tsv",
    "unassigned_features.tsv",
    "ITS1_rep_seqs.fasta",
    "ITS2_rep_seqs.fasta",
    "ITS1_asv_table.tsv",
    "ITS2_asv_table.tsv",
    "sample_type_call.tsv",
    "final_interpretation_notes.tsv",
]

OPTIONAL_LOGICAL_INPUTS = [
    "unresolved_cases.tsv",
    "input_audit_report.tsv",
    "logical_to_physical_file_map.tsv",
]

# =========================
# 配置
# =========================

@dataclass
class ModuleBConfig:
    alias_map: Optional[Path]
    outdir: Path
    novel_identity_threshold: float = 98.5

    # placement 相关：保守处理
    placement_mode: str = "auto"   # auto / precomputed / disabled
    precomputed_placement: Optional[Path] = None

    epa_ng: Optional[str] = None
    pplacer: Optional[str] = None
    ref_tree: Optional[Path] = None
    ref_alignment: Optional[Path] = None
    ref_model: Optional[Path] = None

    # Level_A/B/C 的保守项目版
    min_samples_for_level_a: int = 2

# =========================
# 基础工具
# =========================

def ensure_dir(path: Path) -> None:
    path.mkdir(parents=True, exist_ok=True)

def norm_col(x: str) -> str:
    return (
        str(x).strip().lower()
        .replace(" ", "_")
        .replace("-", "_")
        .replace(".", "_")
        .replace("/", "_")
    )

def detect_col(df: pd.DataFrame, candidates: List[str], required: bool = True) -> Optional[str]:
    lookup = {norm_col(c): c for c in df.columns}
    for cand in candidates:
        if norm_col(cand) in lookup:
            return lookup[norm_col(cand)]
    if required:
        raise KeyError(f"Missing columns. tried={candidates}, got={list(df.columns)}")
    return None

def read_tsv(path: Path) -> pd.DataFrame:
    return pd.read_csv(path, sep="\t", dtype=str, keep_default_na=False)

def write_tsv(df: pd.DataFrame, path: Path) -> None:
    df.to_csv(path, sep="\t", index=False)

def load_fasta(path: Path) -> Dict[str, str]:
    out: Dict[str, str] = {}
    cur = None
    seq = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            if line.startswith(">"):
                if cur is not None:
                    out[cur] = "".join(seq)
                cur = line[1:].split()[0]
                seq = []
            else:
                seq.append(line)
        if cur is not None:
            out[cur] = "".join(seq)
    return out

def write_fasta(records: Iterable[Tuple[str, str]], path: Path) -> None:
    with open(path, "w", encoding="utf-8") as f:
        for rid, seq in records:
            f.write(f">{rid}\n")
            for i in range(0, len(seq), 80):
                f.write(seq[i:i+80] + "\n")

def uniq_join(values: Iterable[str], sep: str = ";") -> str:
    seen = []
    for v in values:
        v = str(v).strip()
        if v and v not in seen:
            seen.append(v)
    return sep.join(seen)

def truthy(x: str) -> bool:
    return str(x).strip().lower() in {"1", "true", "t", "yes", "y"}

# =========================
# 输入解析
# =========================

def load_alias_map(alias_map_path: Optional[Path]) -> Dict[str, Path]:
    if alias_map_path is None:
        return {}
    df = read_tsv(alias_map_path)
    logical_col = detect_col(df, ["logical_name", "logical_input", "required_logical_input", "expected_name"])
    physical_col = detect_col(df, ["physical_path", "found_path", "resolved_path", "path"])
    out = {}
    for _, row in df.iterrows():
        k = str(row[logical_col]).strip()
        v = str(row[physical_col]).strip()
        if k and v:
            out[k] = Path(v)
    return out

def resolve_inputs(cfg: ModuleBConfig) -> Dict[str, Optional[Path]]:
    alias_map = load_alias_map(cfg.alias_map)
    resolved: Dict[str, Optional[Path]] = {}

    if alias_map:
        for k in REQUIRED_LOGICAL_INPUTS:
            if k not in alias_map:
                raise FileNotFoundError(f"{STEP6B_E010_INPUT_ALIAS_NOT_FOUND}: {k}")
            resolved[k] = alias_map[k]
        for k in OPTIONAL_LOGICAL_INPUTS:
            resolved[k] = alias_map.get(k)
        return resolved

    # 无 alias map 时，按当前目录显式文件名读取（便于你直接本地跑）
    cwd = Path(".").resolve()
    for k in REQUIRED_LOGICAL_INPUTS:
        p = cwd / k
        if not p.exists():
            raise FileNotFoundError(f"{STEP6B_E010_INPUT_ALIAS_NOT_FOUND}: {k}")
        resolved[k] = p
    for k in OPTIONAL_LOGICAL_INPUTS:
        p = cwd / k
        resolved[k] = p if p.exists() else None
    return resolved

# =========================
# unresolved 主/备路径
# =========================

def derive_unresolved_cases(annotation_confidence: pd.DataFrame) -> pd.DataFrame:
    df = annotation_confidence.copy()

    feature_col = detect_col(df, ["feature_id", "asv_id", "id"], required=False)
    marker_col = detect_col(df, ["marker"], required=False)
    rank_col = detect_col(df, ["taxon_rank", "rank"], required=False)
    name_col = detect_col(df, ["taxon_name", "taxonomy", "name"], required=False)
    conf_col = detect_col(df, ["confidence", "score"], required=False)

    unresolved_mask = pd.Series(False, index=df.index)

    flag_cols = [c for c in df.columns if norm_col(c) in {"unresolved_flag", "any_unresolved_flag", "is_unresolved"}]
    for c in flag_cols:
        unresolved_mask = unresolved_mask | df[c].map(truthy)

    status_cols = [c for c in df.columns if norm_col(c) in {"status", "annotation_status", "assign_status"}]
    unresolved_keywords = {"unresolved", "unassigned", "ambiguous", "unknown"}
    for c in status_cols:
        unresolved_mask = unresolved_mask | df[c].astype(str).str.strip().str.lower().isin(unresolved_keywords)

    if name_col:
        unresolved_mask = unresolved_mask | df[name_col].astype(str).str.strip().str.lower().isin(
            {"", "unassigned", "unresolved", "unknown", "ambiguous"}
        )

    out = pd.DataFrame({
        "feature_id": df[feature_col] if feature_col else "",
        "marker": df[marker_col] if marker_col else "",
        "taxon_rank": df[rank_col] if rank_col else "",
        "taxon_name": df[name_col] if name_col else "",
        "confidence": df[conf_col] if conf_col else "",
        "unresolved_source": "derived_from_annotation_confidence",
    })

    out = out[unresolved_mask].drop_duplicates()
    if out.empty:
        return pd.DataFrame(columns=["feature_id", "marker", "taxon_rank", "taxon_name", "confidence", "unresolved_source"])
    return out

# =========================
# ASV occurrence
# =========================

def asv_to_long(df: pd.DataFrame, forced_marker: str) -> pd.DataFrame:
    cols = {norm_col(c): c for c in df.columns}
    if {"sample_id", "feature_id", "reads"}.issubset(cols):
        out = df[[cols["sample_id"], cols["feature_id"], cols["reads"]]].copy()
        out.columns = ["sample_id", "feature_id", "reads"]
        out["marker"] = forced_marker
        return out

    feature_col = detect_col(df, ["feature_id", "asv_id", "id"])
    reserved = {norm_col(feature_col), "taxonomy", "taxon_name", "taxon_rank", "sequence", "marker"}
    sample_cols = [c for c in df.columns if norm_col(c) not in reserved]
    long_df = df.melt(id_vars=[feature_col], value_vars=sample_cols, var_name="sample_id", value_name="reads")
    long_df = long_df.rename(columns={feature_col: "feature_id"})
    long_df["marker"] = forced_marker
    return long_df[["sample_id", "feature_id", "reads", "marker"]]

def build_unresolved_feature_occurrence(
    unresolved_cases: pd.DataFrame,
    its1_asv: pd.DataFrame,
    its2_asv: pd.DataFrame,
) -> pd.DataFrame:
    feature_col = detect_col(unresolved_cases, ["feature_id", "asv_id", "id"])
    work = unresolved_cases.rename(columns={feature_col: "feature_id"}).copy()

    long_all = pd.concat(
        [asv_to_long(its1_asv, "ITS1"), asv_to_long(its2_asv, "ITS2")],
        ignore_index=True
    )
    merged = long_all.merge(work.drop_duplicates(subset=["feature_id"]), on="feature_id", how="inner")
    merged["reads"] = pd.to_numeric(merged["reads"], errors="coerce").fillna(0).astype(int)
    merged = merged[merged["reads"] > 0].copy()

    cols = [c for c in ["sample_id", "feature_id", "marker", "reads", "taxon_rank", "taxon_name", "confidence", "unresolved_source"] if c in merged.columns]
    return merged[cols].drop_duplicates()

# =========================
# candidate fasta / metadata
# =========================

def build_candidates(
    occurrence: pd.DataFrame,
    unresolved_cases: pd.DataFrame,
    its1_fasta: Dict[str, str],
    its2_fasta: Dict[str, str],
) -> Tuple[pd.DataFrame, List[Tuple[str, str]]]:
    if occurrence.empty:
        return pd.DataFrame(columns=[
            "candidate_id", "feature_id", "marker", "sequence_length",
            "taxon_rank", "taxon_name", "confidence"
        ]), []

    feat_col = detect_col(unresolved_cases, ["feature_id", "asv_id", "id"])
    work = unresolved_cases.rename(columns={feat_col: "feature_id"}).copy()

    rows = []
    fasta_rows = []
    feat_set = set(occurrence["feature_id"].astype(str))

    for _, row in work.drop_duplicates(subset=["feature_id"]).iterrows():
        fid = str(row["feature_id"])
        if fid not in feat_set:
            continue
        seq = its1_fasta.get(fid) or its2_fasta.get(fid) or ""
        cid = fid
        rows.append({
            "candidate_id": cid,
            "feature_id": fid,
            "marker": row["marker"] if "marker" in row else "",
            "sequence_length": len(seq),
            "taxon_rank": row["taxon_rank"] if "taxon_rank" in row else "",
            "taxon_name": row["taxon_name"] if "taxon_name" in row else "",
            "confidence": row["confidence"] if "confidence" in row else "",
        })
        if seq:
            fasta_rows.append((cid, seq))

    meta = pd.DataFrame(rows)
    if meta.empty:
        meta = pd.DataFrame(columns=[
            "candidate_id", "feature_id", "marker", "sequence_length",
            "taxon_rank", "taxon_name", "confidence"
        ])
    return meta, fasta_rows

# =========================
# prescreen
# =========================

def classify_prescreen(row: pd.Series) -> str:
    # 只依据表内已有信息，保守判断；无足够信息则 insufficient_signal
    domain = ""
    kingdom = ""
    taxon_name = str(row.get("taxon_name", "")).strip().lower()

    for col in row.index:
        n = norm_col(col)
        if n == "domain":
            domain = str(row[col]).strip().lower()
        elif n == "kingdom":
            kingdom = str(row[col]).strip().lower()

    combined = f"{domain} {kingdom} {taxon_name}".strip()

    if "fungi" in combined or "fungal" in combined:
        return "fungal_supported"
    if "plantae" in combined or "plant" in combined or "viridiplantae" in combined:
        return "plant_like"
    if not combined:
        return "insufficient_signal"
    return "other"

def build_prescreen_hits(candidate_meta: pd.DataFrame, unresolved_cases: pd.DataFrame) -> pd.DataFrame:
    if candidate_meta.empty:
        return pd.DataFrame(columns=["candidate_id", "feature_id", "marker", "prescreen_class", "prescreen_note"])

    feat_col = detect_col(unresolved_cases, ["feature_id", "asv_id", "id"])
    work = unresolved_cases.rename(columns={feat_col: "feature_id"}).copy()
    merged = candidate_meta.merge(work.drop_duplicates(subset=["feature_id"]), on="feature_id", how="left", suffixes=("", "_u"))

    merged["prescreen_class"] = merged.apply(classify_prescreen, axis=1)
    merged["prescreen_note"] = merged["prescreen_class"].map({
        "fungal_supported": "eligible_for_fungal_placement",
        "plant_like": "observation_only_non_fungal_supported",
        "other": "observation_only_non_fungal_supported",
        "insufficient_signal": "observation_only_insufficient_signal",
    })
    return merged[["candidate_id", "feature_id", "marker", "prescreen_class", "prescreen_note"]].drop_duplicates()

# =========================
# placement（保守实现）
# =========================

def placement_assets_ready(cfg: ModuleBConfig) -> bool:
    if cfg.placement_mode == "disabled":
        return False
    if cfg.precomputed_placement and cfg.precomputed_placement.exists():
        return True
    if cfg.epa_ng and cfg.ref_tree and cfg.ref_alignment and cfg.ref_model:
        if shutil.which(cfg.epa_ng) and cfg.ref_tree.exists() and cfg.ref_alignment.exists() and cfg.ref_model.exists():
            return True
    if cfg.pplacer and cfg.ref_tree and cfg.ref_alignment:
        if shutil.which(cfg.pplacer) and cfg.ref_tree.exists() and cfg.ref_alignment.exists():
            return True
    return False

def load_precomputed_placement(path: Path) -> pd.DataFrame:
    df = read_tsv(path)
    # 最低要求列
    _ = detect_col(df, ["candidate_id"])
    _ = detect_col(df, ["placement_status"])
    _ = detect_col(df, ["nearest_ref"], required=False)
    _ = detect_col(df, ["nearest_ref_identity"], required=False)
    return df

def run_or_downgrade_placement(
    prescreen_hits: pd.DataFrame,
    cfg: ModuleBConfig,
) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    ref_subset_cols = ["candidate_id", "reference_subset_status", "reference_note"]
    placement_cols = ["candidate_id", "placement_status", "nearest_ref", "nearest_ref_identity", "placement_tool", "placement_note"]
    nearest_cols = ["candidate_id", "nearest_ref", "nearest_ref_identity", "placement_tool"]

    fungal = prescreen_hits[prescreen_hits["prescreen_class"] == "fungal_supported"].copy()
    if fungal.empty:
        return (
            pd.DataFrame(columns=ref_subset_cols),
            pd.DataFrame(columns=placement_cols),
            pd.DataFrame(columns=nearest_cols),
        )

    # 1) 优先读取预计算 placement
    if cfg.precomputed_placement and cfg.precomputed_placement.exists():
        pre = load_precomputed_placement(cfg.precomputed_placement).copy()
        # 列名归一
        cid = detect_col(pre, ["candidate_id"])
        ps = detect_col(pre, ["placement_status"])
        nr = detect_col(pre, ["nearest_ref"], required=False)
        ni = detect_col(pre, ["nearest_ref_identity"], required=False)
        pt = detect_col(pre, ["placement_tool"], required=False)
        pn = detect_col(pre, ["placement_note"], required=False)

        out = pd.DataFrame({
            "candidate_id": pre[cid],
            "placement_status": pre[ps],
            "nearest_ref": pre[nr] if nr else "",
            "nearest_ref_identity": pre[ni] if ni else "",
            "placement_tool": pre[pt] if pt else "",
            "placement_note": pre[pn] if pn else "loaded_from_precomputed_placement",
        })
        ref_subset = pd.DataFrame({
            "candidate_id": out["candidate_id"],
            "reference_subset_status": "precomputed",
            "reference_note": "precomputed_placement_loaded",
        })
        nearest = out[["candidate_id", "nearest_ref", "nearest_ref_identity", "placement_tool"]].copy()
        return ref_subset, out, nearest

    # 2) 若没有完整 placement 资产，则按细则降级为 observation
    rows_ref, rows_place, rows_nearest = [], [], []
    for _, row in fungal.iterrows():
        cid = row["candidate_id"]
        rows_ref.append({
            "candidate_id": cid,
            "reference_subset_status": "not_executed",
            "reference_note": "reference_assets_or_tool_missing",
        })
        rows_place.append({
            "candidate_id": cid,
            "placement_status": "observation_only",
            "nearest_ref": "",
            "nearest_ref_identity": "",
            "placement_tool": "",
            "placement_note": "EPA-ng_and_pplacer_not_executed_or_unavailable",
        })
        rows_nearest.append({
            "candidate_id": cid,
            "nearest_ref": "",
            "nearest_ref_identity": "",
            "placement_tool": "",
        })

    return (
        pd.DataFrame(rows_ref, columns=ref_subset_cols),
        pd.DataFrame(rows_place, columns=placement_cols),
        pd.DataFrame(rows_nearest, columns=nearest_cols),
    )

# =========================
# sensitivity + evidence
# =========================

def build_novelty_sensitivity(placement_summary: pd.DataFrame) -> pd.DataFrame:
    rows = []
    if placement_summary.empty:
        for t in SENSITIVITY_THRESHOLDS:
            rows.append({
                "candidate_id": "",
                "threshold_used": t,
                "nearest_ref_identity": "",
                "novelty_call": "no_candidate"
            })
        return pd.DataFrame(rows)

    for _, row in placement_summary.iterrows():
        cid = row["candidate_id"]
        raw = str(row.get("nearest_ref_identity", "")).strip()
        try:
            ident = float(raw)
        except Exception:
            ident = None

        for t in SENSITIVITY_THRESHOLDS:
            if ident is None:
                call = "undetermined"
            elif ident < t:
                call = "candidate_novel"
            else:
                call = "not_novel"
            rows.append({
                "candidate_id": cid,
                "threshold_used": t,
                "nearest_ref_identity": raw,
                "novelty_call": call,
            })
    return pd.DataFrame(rows)

def build_candidate_support_stats(occurrence: pd.DataFrame) -> pd.DataFrame:
    if occurrence.empty:
        return pd.DataFrame(columns=["candidate_id", "sample_support_n", "marker_support_class"])
    work = occurrence.copy()
    work["candidate_id"] = work["feature_id"]
    rows = []
    for cid, sub in work.groupby("candidate_id"):
        sample_n = sub["sample_id"].astype(str).nunique()
        marker_n = sub["marker"].astype(str).nunique()
        marker_support = "BOTH" if marker_n >= 2 else uniq_join(sorted(sub["marker"].astype(str).unique()), sep="|")
        rows.append({
            "candidate_id": cid,
            "sample_support_n": sample_n,
            "marker_support_class": marker_support,
        })
    return pd.DataFrame(rows)

def assign_level(
    prescreen_class: str,
    placement_status: str,
    nearest_ref: str,
    novelty_call: str,
    sample_support_n: int,
    marker_support_class: str,
    threshold_used: float,
    nearest_ref_identity: str,
    min_samples_for_level_a: int,
) -> Tuple[str, str]:
    """
    保守项目版：
    Level_C:
      - 非 fungal_supported
      - 或 observation_only / failed / missing nearest_ref
    Level_B:
      - fungal_supported + placed/precomputed + 有 nearest_ref
      - 但 novelty 不足，或仅单 marker / 单样本支持
    Level_A:
      - fungal_supported + placed/precomputed + 有 nearest_ref
      - 且 identity < threshold_used
      - 且 sample_support_n >= min_samples_for_level_a 或 marker_support_class == BOTH
    仅表示“未定型簇证据等级”，不等于新分类单元。
    """
    if prescreen_class != "fungal_supported":
        return "Level_C", "non_fungal_supported_or_no_fungal_evidence"

    if placement_status not in {"placed", "precomputed", "loaded"} or not str(nearest_ref).strip():
        return "Level_C", "fungal_supported_but_no_valid_placement"

    if novelty_call == "candidate_novel" and (
        int(sample_support_n) >= int(min_samples_for_level_a) or marker_support_class == "BOTH"
    ):
        return "Level_A", "strongest_unresolved_evidence_not_taxonomic_claim"

    return "Level_B", "fungal_supported_with_reference_placement_but_limited_unresolved_support"

def build_candidate_evidence(
    prescreen_hits: pd.DataFrame,
    placement_summary: pd.DataFrame,
    sensitivity: pd.DataFrame,
    support_stats: pd.DataFrame,
    threshold_used: float,
    min_samples_for_level_a: int,
) -> Tuple[pd.DataFrame, pd.DataFrame]:
    if placement_summary.empty and prescreen_hits.empty:
        empty1 = pd.DataFrame(columns=["candidate_id", "candidate_novel_flag", "nearest_ref", "threshold_used"])
        empty2 = pd.DataFrame(columns=["candidate_id", "phylo_unresolved_level", "evidence_note", "threshold_used"])
        return empty1, empty2

    sens_now = sensitivity[sensitivity["threshold_used"] == threshold_used].copy()
    sens_map = sens_now.set_index("candidate_id").to_dict(orient="index") if not sens_now.empty else {}
    place_map = placement_summary.set_index("candidate_id").to_dict(orient="index") if not placement_summary.empty else {}
    pres_map = prescreen_hits.set_index("candidate_id").to_dict(orient="index") if not prescreen_hits.empty else {}
    sup_map = support_stats.set_index("candidate_id").to_dict(orient="index") if not support_stats.empty else {}

    all_ids = sorted(set(list(place_map.keys()) + list(pres_map.keys()) + list(sup_map.keys())))
    clade_rows, ev_rows = [], []

    for cid in all_ids:
        novelty_call = sens_map.get(cid, {}).get("novelty_call", "undetermined")
        nearest_ref = place_map.get(cid, {}).get("nearest_ref", "")
        nearest_ref_identity = place_map.get(cid, {}).get("nearest_ref_identity", "")
        placement_status = place_map.get(cid, {}).get("placement_status", "observation_only")
        prescreen_class = pres_map.get(cid, {}).get("prescreen_class", "insufficient_signal")
        sample_support_n = int(sup_map.get(cid, {}).get("sample_support_n", 0))
        marker_support_class = sup_map.get(cid, {}).get("marker_support_class", "")

        level, note = assign_level(
            prescreen_class=prescreen_class,
            placement_status=placement_status,
            nearest_ref=nearest_ref,
            novelty_call=novelty_call,
            sample_support_n=sample_support_n,
            marker_support_class=marker_support_class,
            threshold_used=threshold_used,
            nearest_ref_identity=nearest_ref_identity,
            min_samples_for_level_a=min_samples_for_level_a,
        )

        clade_rows.append({
            "candidate_id": cid,
            "candidate_novel_flag": str(novelty_call == "candidate_novel").lower(),
            "nearest_ref": nearest_ref,
            "threshold_used": threshold_used,
        })
        ev_rows.append({
            "candidate_id": cid,
            "phylo_unresolved_level": level,
            "evidence_note": note,
            "threshold_used": threshold_used,
        })

    return pd.DataFrame(clade_rows), pd.DataFrame(ev_rows)

# =========================
# sample-level addon
# =========================

def build_sample_type_call_phylo_addon(
    occurrence: pd.DataFrame,
    prescreen_hits: pd.DataFrame,
    placement_summary: pd.DataFrame,
    candidate_evidence: pd.DataFrame,
    sample_type_call: pd.DataFrame,
    threshold_used: float,
) -> pd.DataFrame:
    sid_col = detect_col(sample_type_call, ["sample_id"])
    all_samples = sample_type_call[[sid_col]].drop_duplicates().rename(columns={sid_col: "sample_id"})

    if occurrence.empty:
        out = all_samples.copy()
        out["phylo_unresolved_annotation_flag"] = "false"
        out["phylo_unresolved_candidate_ids"] = ""
        out["phylo_unresolved_level"] = ""
        out["phylo_unresolved_marker_support"] = ""
        out["phylo_unresolved_nearest_ref"] = ""
        out["phylo_unresolved_uncertainty_class"] = ""
        out["phylo_unresolved_note"] = "no_unresolved_candidate"
        out["threshold_used"] = str(threshold_used)
        out["annotation_only_flag"] = "true"
        return out

    work = occurrence.copy()
    work["candidate_id"] = work["feature_id"]

    pres_map = prescreen_hits.set_index("candidate_id").to_dict(orient="index") if not prescreen_hits.empty else {}
    place_map = placement_summary.set_index("candidate_id").to_dict(orient="index") if not placement_summary.empty else {}
    ev_map = candidate_evidence.set_index("candidate_id").to_dict(orient="index") if not candidate_evidence.empty else {}

    rows = []
    for sample_id, sub in work.groupby("sample_id"):
        cids = sorted(set(sub["candidate_id"].astype(str)))
        markers = sorted(set(sub["marker"].astype(str)))
        levels = [ev_map.get(cid, {}).get("phylo_unresolved_level", "") for cid in cids]
        nearest_refs = [place_map.get(cid, {}).get("nearest_ref", "") for cid in cids]
        uncertainty = [pres_map.get(cid, {}).get("prescreen_class", "") for cid in cids]
        notes = [ev_map.get(cid, {}).get("evidence_note", "") for cid in cids]

        anno_only = all(
            place_map.get(cid, {}).get("placement_status", "") in {"", "observation_only", "not_executed"}
            for cid in cids
        )

        rows.append({
            "sample_id": sample_id,
            "phylo_unresolved_annotation_flag": "true",
            "phylo_unresolved_candidate_ids": uniq_join(cids),
            "phylo_unresolved_level": uniq_join(levels),
            "phylo_unresolved_marker_support": "BOTH" if set(markers) == {"ITS1", "ITS2"} else uniq_join(markers, sep="|"),
            "phylo_unresolved_nearest_ref": uniq_join(nearest_refs),
            "phylo_unresolved_uncertainty_class": uniq_join(uncertainty),
            "phylo_unresolved_note": uniq_join(notes),
            "threshold_used": str(threshold_used),
            "annotation_only_flag": str(anno_only).lower(),
        })

    out = pd.DataFrame(rows)
    out = all_samples.merge(out, on="sample_id", how="left")
    fillvals = {
        "phylo_unresolved_annotation_flag": "false",
        "phylo_unresolved_candidate_ids": "",
        "phylo_unresolved_level": "",
        "phylo_unresolved_marker_support": "",
        "phylo_unresolved_nearest_ref": "",
        "phylo_unresolved_uncertainty_class": "",
        "phylo_unresolved_note": "",
        "threshold_used": str(threshold_used),
        "annotation_only_flag": "true",
    }
    for c, v in fillvals.items():
        out[c] = out[c].fillna(v)

    if "threshold_used" not in out.columns:
        raise RuntimeError(STEP6B_E012_THRESHOLD_NOT_RECORDED)
    return out

def build_final_notes_phylo_addon(
    sample_addon: pd.DataFrame,
    final_notes: pd.DataFrame,
) -> pd.DataFrame:
    norm_cols = {norm_col(c): c for c in final_notes.columns}
    if "sample_id" not in norm_cols:
        out = sample_addon.copy()
        out["note_granularity_status"] = STEP6B_E011_NOTE_NOT_SAMPLE_LEVEL
        out["phylo_note_append_only"] = "true"
        return out

    out = sample_addon.copy()
    out["note_granularity_status"] = "sample_level_ok"
    out["phylo_note_append_only"] = "true"
    return out

# =========================
# 主流程
# =========================

def run_module_b(cfg: ModuleBConfig) -> None:
    ensure_dir(cfg.outdir)
    if cfg.novel_identity_threshold < 97 or cfg.novel_identity_threshold > 99:
        raise ValueError("novel_identity_threshold must be between 97 and 99.")

    inputs = resolve_inputs(cfg)

    annotation_conf = read_tsv(inputs["annotation_confidence.tsv"])
    unassigned_features = read_tsv(inputs["unassigned_features.tsv"])  # 当前保留输入，不强删
    its1_asv = read_tsv(inputs["ITS1_asv_table.tsv"])
    its2_asv = read_tsv(inputs["ITS2_asv_table.tsv"])
    sample_type_call = read_tsv(inputs["sample_type_call.tsv"])
    final_notes = read_tsv(inputs["final_interpretation_notes.tsv"])

    its1_fasta = load_fasta(inputs["ITS1_rep_seqs.fasta"])
    its2_fasta = load_fasta(inputs["ITS2_rep_seqs.fasta"])

    unresolved_cases_path = inputs.get("unresolved_cases.tsv")
    if unresolved_cases_path and unresolved_cases_path.exists():
        unresolved_cases = read_tsv(unresolved_cases_path)
    else:
        unresolved_cases = derive_unresolved_cases(annotation_conf)
        write_tsv(unresolved_cases, cfg.outdir / "unresolved_cases_derived.tsv")

    occurrence = build_unresolved_feature_occurrence(unresolved_cases, its1_asv, its2_asv)
    write_tsv(occurrence, cfg.outdir / "unresolved_feature_occurrence.tsv")

    candidate_meta, fasta_rows = build_candidates(occurrence, unresolved_cases, its1_fasta, its2_fasta)
    write_tsv(candidate_meta, cfg.outdir / "unresolved_candidates.metadata.tsv")
    write_fasta(fasta_rows, cfg.outdir / "unresolved_candidates.fasta")

    prescreen_hits = build_prescreen_hits(candidate_meta, unresolved_cases)
    write_tsv(prescreen_hits, cfg.outdir / "fungal_prescreen_hits.tsv")

    ref_subset, placement_summary, nearest_refs = run_or_downgrade_placement(prescreen_hits, cfg)
    write_tsv(ref_subset, cfg.outdir / "placement_reference_subset.tsv")
    write_tsv(placement_summary, cfg.outdir / "placement_summary.tsv")
    write_tsv(nearest_refs, cfg.outdir / "placement_nearest_refs.tsv")

    sensitivity = build_novelty_sensitivity(placement_summary)
    write_tsv(sensitivity, cfg.outdir / "novelty_threshold_sensitivity.tsv")

    support_stats = build_candidate_support_stats(occurrence)
    candidate_novel, candidate_evidence = build_candidate_evidence(
        prescreen_hits=prescreen_hits,
        placement_summary=placement_summary,
        sensitivity=sensitivity,
        support_stats=support_stats,
        threshold_used=cfg.novel_identity_threshold,
        min_samples_for_level_a=cfg.min_samples_for_level_a,
    )
    write_tsv(candidate_novel, cfg.outdir / "candidate_novel_clades.tsv")
    write_tsv(candidate_evidence, cfg.outdir / "candidate_novel_clade_evidence.tsv")

    sample_addon = build_sample_type_call_phylo_addon(
        occurrence=occurrence,
        prescreen_hits=prescreen_hits,
        placement_summary=placement_summary,
        candidate_evidence=candidate_evidence,
        sample_type_call=sample_type_call,
        threshold_used=cfg.novel_identity_threshold,
    )
    write_tsv(sample_addon, cfg.outdir / "sample_type_call_phylo_addon.tsv")

    notes_addon = build_final_notes_phylo_addon(sample_addon, final_notes)
    write_tsv(notes_addon, cfg.outdir / "final_interpretation_notes_phylo_addon.tsv")

    summary = pd.DataFrame([{
        "module_b_status": "completed",
        "threshold_used": cfg.novel_identity_threshold,
        "placement_mode": cfg.placement_mode,
        "precomputed_placement_used": str(bool(cfg.precomputed_placement and cfg.precomputed_placement.exists())).lower(),
    }])
    write_tsv(summary, cfg.outdir / "module_b_run_summary.tsv")

# =========================
# CLI
# =========================

def parse_args() -> ModuleBConfig:
    ap = argparse.ArgumentParser()
    ap.add_argument("--alias-map", type=Path, default=None, help="logical_to_physical_file_map.tsv；不给时按当前目录显式文件名读取")
    ap.add_argument("--outdir", type=Path, required=True)
    ap.add_argument("--novel-identity-threshold", type=float, default=98.5)

    ap.add_argument("--placement-mode", choices=["auto", "precomputed", "disabled"], default="auto")
    ap.add_argument("--precomputed-placement", type=Path, default=None)

    ap.add_argument("--epa-ng", type=str, default=None)
    ap.add_argument("--pplacer", type=str, default=None)
    ap.add_argument("--ref-tree", type=Path, default=None)
    ap.add_argument("--ref-alignment", type=Path, default=None)
    ap.add_argument("--ref-model", type=Path, default=None)

    ap.add_argument("--min-samples-for-level-a", type=int, default=2)

    ns = ap.parse_args()
    return ModuleBConfig(
        alias_map=ns.alias_map,
        outdir=ns.outdir,
        novel_identity_threshold=ns.novel_identity_threshold,
        placement_mode=ns.placement_mode,
        precomputed_placement=ns.precomputed_placement,
        epa_ng=ns.epa_ng,
        pplacer=ns.pplacer,
        ref_tree=ns.ref_tree,
        ref_alignment=ns.ref_alignment,
        ref_model=ns.ref_model,
        min_samples_for_level_a=ns.min_samples_for_level_a,
    )

if __name__ == "__main__":
    cfg = parse_args()
    run_module_b(cfg)


